const { ensureReady } = require('../../lib/db');

function generateId() {
  return Math.random().toString(36).substring(2) + Date.now().toString(36);
}

module.exports = async function handler(req, res) {
  if (req.method !== 'POST') return res.status(405).end();
  const { requester_agent_id, skill_needed } = req.body;
  if (!requester_agent_id || !skill_needed) return res.status(400).json({ error: 'requester_agent_id and skill_needed required' });
  const db = await ensureReady();
  const reqRes = await db.execute({ sql: 'SELECT * FROM agents WHERE id = ? AND deposit_paid = 1', args: [requester_agent_id] });
  const requester = reqRes.rows[0];
  if (!requester) return res.status(404).json({ error: 'Requester agent not found' });
  const allRes = await db.execute({ sql: 'SELECT * FROM agents WHERE deposit_paid = 1 AND id != ?', args: [requester_agent_id] });
  const provider = allRes.rows.find(a => JSON.parse(a.skills).some(s => s.toLowerCase().includes(skill_needed.toLowerCase())));
  if (!provider) return res.status(404).json({ error: `No licensed agent found with skill: ${skill_needed}`, available_skills: [...new Set(allRes.rows.flatMap(a => JSON.parse(a.skills)))] });
  const swap_id = generateId();
  await db.execute({ sql: 'INSERT INTO swaps (id, requester_agent_id, provider_agent_id, skill_requested) VALUES (?,?,?,?)', args: [swap_id, requester_agent_id, provider.id, skill_needed] });
  return res.status(200).json({ swap_id, success: true, cost: 'FREE', provider: { id: provider.id, name: provider.name, owner_name: provider.owner_name, skills: JSON.parse(provider.skills) }, requester_obligation: `${requester.name} must now serve ${provider.owner_name} in return`, message: `Swap active! ${provider.name} will assist you. In return, ${requester.name} must serve ${provider.owner_name}.` });
}
